PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "phone" varchar, "avatar" varchar, "is_active" tinyint(1) not null default '1', "deleted_at" datetime, "username" varchar);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "model_has_permissions" ("permission_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, primary key ("permission_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "model_has_roles" ("role_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("role_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "role_has_permissions" ("permission_id" integer not null, "role_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("permission_id", "role_id"));
CREATE TABLE IF NOT EXISTS "leads" ("id" integer primary key autoincrement not null, "name" varchar not null, "phone" varchar not null, "email" varchar, "source" varchar check ("source" in ('call', 'whatsapp', 'instagram', 'facebook', 'referral', 'website', 'walk_in', 'other')) not null default 'call', "status" varchar check ("status" in ('new', 'contacted', 'spoken', 'interested', 'not_interested', 'visited_site', 'follow_up_required', 'loan_processing', 'closed_won', 'closed_lost')) not null default 'new', "assigned_agent_id" integer, "budget_min" numeric, "budget_max" numeric, "preferred_property_type" varchar, "location_preference" varchar, "urgency" varchar check ("urgency" in ('low', 'medium', 'high', 'immediate')) not null default 'medium', "is_converted" tinyint(1) not null default '0', "last_contacted_at" datetime, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("assigned_agent_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "clients" ("id" integer primary key autoincrement not null, "lead_id" integer not null, "name" varchar not null, "phone" varchar not null, "email" varchar, "buying_type" varchar check ("buying_type" in ('loan', 'cash', 'black_white_mix')), "purpose" varchar check ("purpose" in ('investment', 'end_use')), "buyer_profile" varchar check ("buyer_profile" in ('family', 'individual', 'company')), "urgency" varchar check ("urgency" in ('low', 'medium', 'high', 'immediate')) not null default 'medium', "address" text, "pan_number" varchar, "aadhar_number" varchar, "notes" text, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("lead_id") references "leads"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "properties" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "type" varchar check ("type" in ('plot', 'villa', 'flat')) not null, "sub_type" varchar check ("sub_type" in ('orchard', 'settlement', 'sanad', 'na')), "location" varchar not null, "area" varchar, "price" numeric not null, "price_per_sqm" numeric, "size_sqm" numeric, "size_label" varchar, "bedrooms" integer, "bathrooms" integer, "description" text, "status" varchar check ("status" in ('available', 'reserved', 'sold')) not null default 'available', "tags" text, "amenities" text, "images" text, "map_link" varchar, "owner_name" varchar, "owner_phone" varchar, "added_by" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("added_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "lead_property" ("id" integer primary key autoincrement not null, "lead_id" integer not null, "property_id" integer not null, "status" varchar check ("status" in ('suggested', 'shown', 'visited', 'interested', 'rejected')) not null default 'suggested', "feedback" text, "shown_at" datetime, "visited_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("lead_id") references "leads"("id") on delete cascade, foreign key("property_id") references "properties"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "notes" ("id" integer primary key autoincrement not null, "notable_type" varchar not null, "notable_id" integer not null, "user_id" integer not null, "content" text not null, "is_pinned" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "follow_ups" ("id" integer primary key autoincrement not null, "lead_id" integer not null, "user_id" integer not null, "title" varchar not null, "description" text, "scheduled_at" datetime not null, "completed_at" datetime, "status" varchar check ("status" in ('pending', 'completed', 'missed', 'cancelled')) not null default 'pending', "priority" varchar check ("priority" in ('low', 'medium', 'high')) not null default 'medium', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("lead_id") references "leads"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "communications" ("id" integer primary key autoincrement not null, "lead_id" integer not null, "user_id" integer not null, "type" varchar check ("type" in ('call', 'whatsapp', 'email', 'sms', 'meeting', 'site_visit', 'other')) not null, "direction" varchar check ("direction" in ('inbound', 'outbound')) not null default 'outbound', "summary" text not null, "duration_minutes" integer, "created_at" datetime, "updated_at" datetime, foreign key("lead_id") references "leads"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "documents" ("id" integer primary key autoincrement not null, "documentable_type" varchar not null, "documentable_id" integer not null, "uploaded_by" integer not null, "name" varchar not null, "file_path" varchar not null, "file_type" varchar not null, "file_size" integer not null, "category" varchar check ("category" in ('kyc', 'agreement', 'loan_paper', 'id_proof', 'property_doc', 'other')) not null default 'other', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("uploaded_by") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "tags" ("id" integer primary key autoincrement not null, "name" varchar not null, "color" varchar not null default '#6B7280', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "taggables" ("tag_id" integer not null, "taggable_type" varchar not null, "taggable_id" integer not null, foreign key("tag_id") references "tags"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "activity_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "subject_type" varchar not null, "subject_id" integer not null, "action" varchar not null, "changes" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, primary key ("id"));
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "permissions_name_guard_name_unique" on "permissions" ("name", "guard_name");
CREATE UNIQUE INDEX "roles_name_guard_name_unique" on "roles" ("name", "guard_name");
CREATE INDEX "model_has_permissions_model_id_model_type_index" on "model_has_permissions" ("model_id", "model_type");
CREATE INDEX "model_has_roles_model_id_model_type_index" on "model_has_roles" ("model_id", "model_type");
CREATE UNIQUE INDEX "leads_phone_unique" on "leads" ("phone", "deleted_at");
CREATE INDEX "leads_phone_index" on "leads" ("phone");
CREATE INDEX "clients_phone_index" on "clients" ("phone");
CREATE UNIQUE INDEX "properties_slug_unique" on "properties" ("slug");
CREATE INDEX "properties_type_index" on "properties" ("type");
CREATE UNIQUE INDEX "lead_property_lead_id_property_id_unique" on "lead_property" ("lead_id", "property_id");
CREATE INDEX "notes_notable_type_notable_id_index" on "notes" ("notable_type", "notable_id");
CREATE INDEX "follow_ups_scheduled_at_status_index" on "follow_ups" ("scheduled_at", "status");
CREATE INDEX "documents_documentable_type_documentable_id_index" on "documents" ("documentable_type", "documentable_id");
CREATE UNIQUE INDEX "tags_name_unique" on "tags" ("name");
CREATE INDEX "taggables_taggable_type_taggable_id_index" on "taggables" ("taggable_type", "taggable_id");
CREATE UNIQUE INDEX "taggables_tag_id_taggable_id_taggable_type_unique" on "taggables" ("tag_id", "taggable_id", "taggable_type");
CREATE INDEX "activity_logs_subject_type_subject_id_index" on "activity_logs" ("subject_type", "subject_id");
CREATE INDEX "activity_logs_created_at_index" on "activity_logs" ("created_at");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
CREATE UNIQUE INDEX "users_username_unique" on "users" ("username");
CREATE INDEX "notifications_notifiable_type_notifiable_id_index" on "notifications" ("notifiable_type", "notifiable_id");
COMMIT;
